static __attribute__((target("avx2,fma"))) void
radix7_n1_scaled_fwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    size_t is, size_t os, size_t vl, double scale)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d KP623 = _mm256_set1_pd(0.623489801858733483364005678595276549458503723);
    const __m256d KP222 = _mm256_set1_pd(0.222520933956314392876407737276167608797550201);
    const __m256d KP900 = _mm256_set1_pd(0.900968867902419145998749172576935961842536926);
    const __m256d KP974 = _mm256_set1_pd(0.974927912181823619341969333618180826306343079);
    const __m256d KP781 = _mm256_set1_pd(0.781831482468029803634124164091190323233604431);
    const __m256d KP433 = _mm256_set1_pd(0.433883739117558120401696442058891989290714264);
    (void)sign_flip;  /* reserved for neg() */

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im;
    __m256d x4_re,x4_im,x5_re,x5_im,x6_re,x6_im;
    __attribute__((aligned(32))) __m256d spill_re_buf[6];
    __attribute__((aligned(32))) __m256d spill_im_buf[6];
    double * __restrict__ spill_re = (double*)spill_re_buf;
    double * __restrict__ spill_im = (double*)spill_im_buf;
    __m256d ar,ai,br,bi,cr,ci,dr,di,er,ei,fr,fi;
    __m256d R1r,R1i,R2r,R2i,R3r,R3i;

    const __m256d vscale = _mm256_set1_pd(scale);

    for (size_t k = 0; k < vl; k += 4) {
        x0_re = LD(&in_re[0*is+k]);
        x0_im = LD(&in_im[0*is+k]);
        x1_re = LD(&in_re[1*is+k]);
        x1_im = LD(&in_im[1*is+k]);
        x2_re = LD(&in_re[2*is+k]);
        x2_im = LD(&in_im[2*is+k]);
        x3_re = LD(&in_re[3*is+k]);
        x3_im = LD(&in_im[3*is+k]);
        x4_re = LD(&in_re[4*is+k]);
        x4_im = LD(&in_im[4*is+k]);
        x5_re = LD(&in_re[5*is+k]);
        x5_im = LD(&in_im[5*is+k]);
        x6_re = LD(&in_re[6*is+k]);
        x6_im = LD(&in_im[6*is+k]);

        /* DFT-7 butterfly [fwd] */
        /* Phase 1 — symmetric/antisymmetric pairs */
        ar=_mm256_add_pd(x1_re,x6_re); ai=_mm256_add_pd(x1_im,x6_im);
        dr=_mm256_sub_pd(x1_re,x6_re); di=_mm256_sub_pd(x1_im,x6_im);
        br=_mm256_add_pd(x2_re,x5_re); bi=_mm256_add_pd(x2_im,x5_im);
        er=_mm256_sub_pd(x2_re,x5_re); ei=_mm256_sub_pd(x2_im,x5_im);
        cr=_mm256_add_pd(x3_re,x4_re); ci=_mm256_add_pd(x3_im,x4_im);
        fr=_mm256_sub_pd(x3_re,x4_re); fi=_mm256_sub_pd(x3_im,x4_im);
        /* Spill diffs d,e,f */
        _mm256_store_pd(&spill_re[0*4], dr);
        _mm256_store_pd(&spill_im[0*4], di);
        _mm256_store_pd(&spill_re[1*4], er);
        _mm256_store_pd(&spill_im[1*4], ei);
        _mm256_store_pd(&spill_re[2*4], fr);
        _mm256_store_pd(&spill_im[2*4], fi);

        /* Phase 2 — R-term first level + y0 + R completion */
        /* 3 independent R seeds from x0 (critical path: 1 FMA latency) */
        { __m256d t1r=_mm256_fnmadd_pd(KP900,cr,x0_re), t1i=_mm256_fnmadd_pd(KP900,ci,x0_im);
          __m256d t2r=_mm256_fnmadd_pd(KP222,ar,x0_re), t2i=_mm256_fnmadd_pd(KP222,ai,x0_im);
          __m256d t3r=_mm256_fnmadd_pd(KP900,ar,x0_re), t3i=_mm256_fnmadd_pd(KP900,ai,x0_im);
          R1r=_mm256_fmadd_pd(KP623,ar,_mm256_fnmadd_pd(KP222,br,t1r));
          R1i=_mm256_fmadd_pd(KP623,ai,_mm256_fnmadd_pd(KP222,bi,t1i));
          R2r=_mm256_fmadd_pd(KP623,cr,_mm256_fnmadd_pd(KP900,br,t2r));
          R2i=_mm256_fmadd_pd(KP623,ci,_mm256_fnmadd_pd(KP900,bi,t2i));
          R3r=_mm256_fnmadd_pd(KP222,cr,_mm256_fmadd_pd(KP623,br,t3r));
          R3i=_mm256_fnmadd_pd(KP222,ci,_mm256_fmadd_pd(KP623,bi,t3i)); }
        x0_re=_mm256_add_pd(x0_re,_mm256_add_pd(_mm256_add_pd(ar,br),cr));
        x0_im=_mm256_add_pd(x0_im,_mm256_add_pd(_mm256_add_pd(ai,bi),ci));
        /* Spill R1, R2, R3  (a,b,c,x0 dead after this) */
        _mm256_store_pd(&spill_re[3*4], R1r);
        _mm256_store_pd(&spill_im[3*4], R1i);
        _mm256_store_pd(&spill_re[4*4], R2r);
        _mm256_store_pd(&spill_im[4*4], R2i);
        _mm256_store_pd(&spill_re[5*4], R3r);
        _mm256_store_pd(&spill_im[5*4], R3i);

        /* Phase 3 — sine S terms + combine */
        dr = _mm256_load_pd(&spill_re[0*4]);
        di = _mm256_load_pd(&spill_im[0*4]);
        er = _mm256_load_pd(&spill_re[1*4]);
        ei = _mm256_load_pd(&spill_im[1*4]);
        fr = _mm256_load_pd(&spill_re[2*4]);
        fi = _mm256_load_pd(&spill_im[2*4]);

        /* Pair k=1 -> y1, y6 */
        R1r = _mm256_load_pd(&spill_re[3*4]);
        R1i = _mm256_load_pd(&spill_im[3*4]);
        { __m256d S1re=_mm256_fmadd_pd(KP433,fi,_mm256_fmadd_pd(KP974,ei,_mm256_mul_pd(KP781,di)));
          __m256d S1pos=_mm256_fmadd_pd(KP433,fr,_mm256_fmadd_pd(KP974,er,_mm256_mul_pd(KP781,dr)));
          x1_re=_mm256_add_pd(R1r,S1re); x1_im=_mm256_sub_pd(R1i,S1pos);
          x6_re=_mm256_sub_pd(R1r,S1re); x6_im=_mm256_add_pd(R1i,S1pos); }

        /* Pair k=2 -> y2, y5 */
        R2r = _mm256_load_pd(&spill_re[4*4]);
        R2i = _mm256_load_pd(&spill_im[4*4]);
        { __m256d S2re=_mm256_fmsub_pd(KP974,di,_mm256_fmadd_pd(KP433,ei,_mm256_mul_pd(KP781,fi)));
          __m256d S2pos=_mm256_fmsub_pd(KP974,dr,_mm256_fmadd_pd(KP433,er,_mm256_mul_pd(KP781,fr)));
          x2_re=_mm256_add_pd(R2r,S2re); x2_im=_mm256_sub_pd(R2i,S2pos);
          x5_re=_mm256_sub_pd(R2r,S2re); x5_im=_mm256_add_pd(R2i,S2pos); }

        /* Pair k=3 -> y3, y4 */
        R3r = _mm256_load_pd(&spill_re[5*4]);
        R3i = _mm256_load_pd(&spill_im[5*4]);
        { __m256d S3re=_mm256_fmadd_pd(KP974,fi,_mm256_fnmadd_pd(KP781,ei,_mm256_mul_pd(KP433,di)));
          __m256d S3pos=_mm256_fmadd_pd(KP974,fr,_mm256_fnmadd_pd(KP781,er,_mm256_mul_pd(KP433,dr)));
          x3_re=_mm256_add_pd(R3r,S3re); x3_im=_mm256_sub_pd(R3i,S3pos);
          x4_re=_mm256_sub_pd(R3r,S3re); x4_im=_mm256_add_pd(R3i,S3pos); }

        ST(&out_re[0*os+k], _mm256_mul_pd(vscale, x0_re));
        ST(&out_im[0*os+k], _mm256_mul_pd(vscale, x0_im));
        ST(&out_re[1*os+k], _mm256_mul_pd(vscale, x1_re));
        ST(&out_im[1*os+k], _mm256_mul_pd(vscale, x1_im));
        ST(&out_re[2*os+k], _mm256_mul_pd(vscale, x2_re));
        ST(&out_im[2*os+k], _mm256_mul_pd(vscale, x2_im));
        ST(&out_re[3*os+k], _mm256_mul_pd(vscale, x3_re));
        ST(&out_im[3*os+k], _mm256_mul_pd(vscale, x3_im));
        ST(&out_re[4*os+k], _mm256_mul_pd(vscale, x4_re));
        ST(&out_im[4*os+k], _mm256_mul_pd(vscale, x4_im));
        ST(&out_re[5*os+k], _mm256_mul_pd(vscale, x5_re));
        ST(&out_im[5*os+k], _mm256_mul_pd(vscale, x5_im));
        ST(&out_re[6*os+k], _mm256_mul_pd(vscale, x6_re));
        ST(&out_im[6*os+k], _mm256_mul_pd(vscale, x6_im));
    }
}

